import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Cookie from 'cookie-universal';
import Axios, { COURSES, ADMIN_COURSES } from '../../Api/Api';
import '../../styles/Dashboard.css';

export default function Dashboard() {
  const navigate = useNavigate();
  const cookie = Cookie();

  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [currentCourse, setCurrentCourse] = useState(null);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    price: '',
    rating: '',
    image: '',
    instructor_name: '',
    is_featured: false
  });
  const [formLoading, setFormLoading] = useState(false);

  // دالة للحصول على بيانات المستخدم
  function getCurrentUser() {
    const user = cookie.get('educational-user');
    if (!user) return null;
    
    // إذا كان String → حوّله لـ Object
    // إذا كان Object → أرجعه مباشرة
    return typeof user === 'string' ? JSON.parse(user) : user;
  }

  // التحقق من الأدمن
  useEffect(() => {
    const userData = getCurrentUser();
    
    if (!userData) {
      navigate('/login');
      return;
    }

    if (userData.role !== 'admin') {
      alert('غير مصرح لك بالوصول لهذه الصفحة');
      navigate('/');
      return;
    }

    loadCourses();
  }, []);

  // ... باقي الكود بدون تغيير
  
  // جلب الكورسات
  function loadCourses() {
    setLoading(true);
    Axios.get(`/${COURSES}`)
      .then(res => {
        setCourses(res.data);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  }

  // فتح Modal للإضافة
  function openAddModal() {
    setEditMode(false);
    setCurrentCourse(null);
    setFormData({
      title: '',
      description: '',
      price: '',
      rating: '',
      image: '',
      instructor_name: '',
      is_featured: false
    });
    setShowModal(true);
  }

  // فتح Modal للتعديل
  function openEditModal(course) {
    setEditMode(true);
    setCurrentCourse(course);
    setFormData({
      title: course.title,
      description: course.description,
      price: course.price,
      rating: course.rating,
      image: course.image,
      instructor_name: course.instructor_name || '',
      is_featured: course.is_featured || false
    });
    setShowModal(true);
  }

  // معالجة التغييرات بالـ Form
  function handleChange(e) {
    const { name, value, type, checked } = e.target;
    setFormData({
      ...formData,
      [name]: type === 'checkbox' ? checked : value
    });
  }

  // إضافة/تعديل كورس
  async function handleSubmit(e) {
    e.preventDefault();
    setFormLoading(true);

    try {
      if (editMode) {
        await Axios.put(`/${ADMIN_COURSES}/${currentCourse.id}`, formData);
        alert('تم تعديل الكورس بنجاح ✅');
      } else {
        await Axios.post(`/${ADMIN_COURSES}`, formData);
        alert('تم إضافة الكورس بنجاح ✅');
      }

      setShowModal(false);
      loadCourses();
      setFormLoading(false);
    } catch (error) {
      console.error(error);
      alert('حدث خطأ: ' + (error.response?.data?.message || 'حاول مرة أخرى'));
      setFormLoading(false);
    }
  }

  // حذف كورس
  async function handleDelete(id, title) {
    if (!window.confirm(`هل أنت متأكد من حذف الكورس "${title}"؟`)) {
      return;
    }

    try {
      await Axios.delete(`/${ADMIN_COURSES}/${id}`);
      alert('تم حذف الكورس بنجاح ✅');
      loadCourses();
    } catch (error) {
      console.error(error);
      alert('حدث خطأ في الحذف');
    }
  }

  if (loading) {
    return (
      <div className="loading-container">
        <div className="spinner"></div>
        <p>جاري التحميل...</p>
      </div>
    );
  }

  return (
    <div className="dashboard-page">
      {/* باقي الكود نفسه... */}
      {/* (نفس الـ JSX اللي أعطيتك إياه قبل) */}
    </div>
  );
}
